mapper.select:
SELECT B1.* FROM ( SELECT A1.* , ROW_NUMBER() OVER () AS PAGEINDEX FROM ( SELECT request.TITLE AS title /* 제목명*/ , ( SELECT USER_NM FROM DOCS_USER tmp WHERE tmp.USER_ID = request.INSERT_UID ) AS insertUserNm , request.INSERT_DT AS insertDt /* 등록일 */ , request.HIT_COUNT AS hitCount /*조회수*/ , request.NOTICE_CD AS noticeCd /* 글번호 */ , request.START_DT AS startDt /* 개시 시작일*/ , request.END_DT AS endDt /* 개시 종료일 */ FROM DOCS_NOTICE request WHERE 1 = 1
AND request.INSERT_DT BETWEEN TO_DATE(#{insertStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{insertEndDt}, 'YYYY-MM-DD') + INTERVAL '1 day'
AND DEL_YN = 'N'
AND TITLE LIKE '%' || #{title} || '%'
AND INSERT_UID = #{insertUserNm}
ORDER BY insertDt DESC
ORDER BY ${sortColumn} ${order}
) A1 WHERE 1=1
LIMIT #{end}
) B1
WHERE PAGEINDEX >= #{start}

mapper.update:
UPDATE DOCS_NOTICE
SET HIT_COUNT = COALESCE(HIT_COUNT,0) + 1
WHERE NOTICE_CD = #{noticeCd}

UPDATE DOCS_NOTICE
SET TITLE = #{noticeTitle}
  , CONTENTS = #{contents}
  , UPDATE_UID = #{sessionUser.userId}
  , UPDATE_DT = CURRENT_TIMESTAMP
  , START_DT = replace(#{startDt}, '-', '')
  , END_DT = replace(#{endDt}, '-', '')
WHERE NOTICE_CD = #{noticeCd}

UPDATE DOCS_NOTICE
SET DEL_YN = 'Y'
WHERE NOTICE_CD = #{noticeCd}
